        local rhs = self:process_expr(expr.rhsoperand)
        local op = expr.operator.text
        local opName = self.binaryOperatorNames[op]
        if opName then return string.format(\\"%s%s(%s, %s)\\", self.callId, opName, lhs, rhs) end
