            if symbol == \\"+\\" then res = valA + valB
            elseif symbol == \\"-\\" then res = valA - valB
            elseif symbol == \\"*\\" then res = valA * valB
            elseif symbol == \\"/\\" then res = valB ~= 0 and valA / valB or 0
            elseif symbol == \\"%\\" then res = valB ~= 0 and valA % valB or 0
