    end
    meta.__lt = function(a, b)
        local valA = typeFunction(a) == \\"table\\" and rawget(a, \\"__value\\") or a
        local valB = typeFunction(b) == \\"table\\" and rawget(b, \\"__value\\") or b
        return valA < valB
    end
    meta.__le = function(a, b)
        local valA = typeFunction(a) == \\"table\\" and rawget(a, \\"__value\\") or a
