                        local funcSignature = defaultParam ~= '\\"' and \\"function(\\" .. \\"bI\\" .. \\")\\" or \\"function()\\"
                        local indent = string.rep(\\"    \\", dumperState.indent + 2)
                        local funcBody = {}
