                table.insert(argStrings, \\"{\n\\" .. string.rep(\\"    \\", dumperState.indent + 1) .. table.concat(tableParts, \\",\n\\" .. string.rep(\\"    \\", dumperState.indent + 1)) .. \\"\n\\" .. string.rep(\\"    \\", dumperState.indent) .. \\"}\\")
            elseif typeFunction(val) == \\"function\\" then
