            [\\"BasePart.Touched\\"]             = {{Name=\\"otherPart\\", Type=\\"BasePart\\"}},
            [\\"BasePart.TouchEnded\\"]          = {{Name=\\"otherPart\\", Type=\\"BasePart\\"}},
