            rawCode = rawCode:gsub(\\"([%a_][%w_]*)(%b[])\\", function(name, firstBracket)
                -- check if after firstBracket there are more brackets then the operator
                return name .. firstBracket
            end)
            -- proper scan: replace lval+= where lval is ident + bracket chain
            do
                local result = {}
                local i = 1
                local len = #rawCode
                while i <= len do
                    -- look for identifier start
                    local idStart, idEnd = rawCode:find(\\"[%a_][%w_]*\\", i)
                    if not idStart then
                        result[#result+1] = rawCode:sub(i)
                        break
                    end
                    result[#result+1] = rawCode:sub(i, idStart-1)
                    local varName = rawCode:match(\\"[%a_][%w_]*\\", idStart)
                    local pos = idStart + #varName
                    -- consume bracket chains
                    while pos <= len and rawCode:sub(pos,pos) == \\"[\\" do
                        local _, bEnd = rawCode:find(\\"%b[]\\", pos)
                        if not bEnd then break end
                        varName = varName .. rawCode:sub(pos, bEnd)
                        pos = bEnd + 1
                    end
                    -- check for operator after optional whitespace
                    local wsEnd = pos
                    while wsEnd <= len and rawCode:sub(wsEnd,wsEnd):match(\\"%s\\") do wsEnd=wsEnd+1 end
                    local opMatch = rawCode:sub(wsEnd, wsEnd + #operatorAssignment - 1)
                    if opMatch == operatorAssignment and varName:find(\\"%[\\") then
                        -- rewrite: varName op= ... -> varName = varName op ...
                        result[#result+1] = varName .. \\" = \\" .. varName .. \\" \\" .. operator .. \\" \\"
                        i = wsEnd + #operatorAssignment
                    else
